#!/usr/bin/env python3
"""
geoip_last: reads /var/log/wtmp and prints GeoIP city/country for each login IP.
Requires: pip install requests
"""

import struct
import socket
import sys
import ipaddress
import requests

# struct utmp layout (Linux, matches last.c)
# See /usr/include/bits/utmp.h
UT_LINESIZE = 32
UT_NAMESIZE = 32
UT_HOSTSIZE = 256

UTMP_STRUCT = f"hi32s{UT_LINESIZE}s{UT_NAMESIZE}s{UT_HOSTSIZE}sHHiI4i20s"
UTMP_SIZE = struct.calcsize(UTMP_STRUCT)

WTMP_FILE = "/var/log/wtmp"


def read_wtmp(path=WTMP_FILE):
    ips = []
    try:
        with open(path, "rb") as f:
            while chunk := f.read(UTMP_SIZE):
                if len(chunk) < UTMP_SIZE:
                    break
                fields = struct.unpack(UTMP_STRUCT, chunk)
                host = fields[5].decode(errors="ignore").rstrip("\x00")
                if host:
                    # host may be a hostname or IP
                    try:
                        ipaddress.ip_address(host)
                        ips.append(host)
                    except ValueError:
                        # resolve hostname to IP
                        try:
                            ip = socket.gethostbyname(host)
                            ips.append(ip)
                        except socket.gaierror:
                            pass
    except FileNotFoundError:
        print(f"Error: {path} not found", file=sys.stderr)
        sys.exit(1)
    return ips


def geoip_lookup(ip):
    try:
        r = requests.get(f"http://ip-api.com/json/{ip}?fields=status,city,country", timeout=5)
        data = r.json()
        if data.get("status") == "success":
            return data.get("city", "?"), data.get("country", "?")
    except Exception:
        pass
    return "?", "?"


def main():
    path = sys.argv[1] if len(sys.argv) > 1 else WTMP_FILE
    ips = read_wtmp(path)

    if not ips:
        print("No IPs found in wtmp.")
        return

    seen = {}
    print(f"{'IP':<40} {'City':<20} {'Country'}")
    print("-" * 70)
    for ip in ips:
        if ip not in seen:
            city, country = geoip_lookup(ip)
            seen[ip] = (city, country)
        city, country = seen[ip]
        print(f"{ip:<40} {city:<20} {country}")


if __name__ == "__main__":
    main()

