// ── Resolve hostname → IP string ──────────────────────────────────────────────
static std::string resolve(const char* host) {
    struct in_addr a{}; struct in6_addr a6{};
    if (inet_pton(AF_INET, host, &a) == 1 || inet_pton(AF_INET6, host, &a6) == 1)
